export const getConfirmPaymentUrl = (id: number,) => {




  return `/api/payments/${id}/confirm`
}

/**
 * @summary Confirm payment
 */
export const confirmPayment = async (id: number,
    paymentConfirm: PaymentConfirm, options?: RequestInit): Promise<Payment> => {

  return customFetch<Payment>(getConfirmPaymentUrl(id),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      paymentConfirm,)
  }
);}




export const getConfirmPaymentMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof confirmPayment>>, TError,{id: number;data: BodyType<PaymentConfirm>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof confirmPayment>>, TError,{id: number;data: BodyType<PaymentConfirm>}, TContext> => {

const mutationKey = ['confirmPayment'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof confirmPayment>>, {id: number;data: BodyType<PaymentConfirm>}> = (props) => {
          const {id,data} = props ?? {};

          return  confirmPayment(id,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type ConfirmPaymentMutationResult = NonNullable<Awaited<ReturnType<typeof confirmPayment>>>
    export type ConfirmPaymentMutationBody = BodyType<PaymentConfirm>
    export type ConfirmPaymentMutationError = ErrorType<unknown>

    /**
 * @summary Confirm payment
 */
