    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof confirmPayment>>, TError,{id: number;data: BodyType<PaymentConfirm>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof confirmPayment>>,
        TError,
        {id: number;data: BodyType<PaymentConfirm>},
        TContext
      > => {
      return useMutation(getConfirmPaymentMutationOptions(options));
    }

